/**
 * Path-based router for the Motivation PWA.
 * Leans heavily on the Navigation API (supported on all target devices).
 */

export interface RouteContext {
    path: string;
    params: Record<string, string>;
    query: URLSearchParams;
}

export interface RouteConfig {
    render: (ctx: RouteContext) => HTMLElement | Promise<HTMLElement>;
}

// ── Navigation helpers ──────────────────────────────────────────────────────

export function navigate(path: string, options?: { history?: 'push' | 'replace' }): void {
    const url = path.startsWith('/') ? path : `/${path}`;
    window.navigation.navigate(url, options?.history ? { history: options.history } : undefined);
}

export function goBack(fallbackPath = '/'): void {
    const prevEntry = window.navigation.entries()[window.navigation.currentEntry!.index - 1];

    if (prevEntry) {
        void window.navigation.back().finished!.catch(() => {
            navigate(fallbackPath, { history: 'replace' });
        });
        return;
    }

    navigate(fallbackPath, { history: 'replace' });
}

/**
 * Jump back in history past a multi-step flow to the first entry whose path is
 * not a flow step. `flowPrefixes` matches a path if it equals the prefix or
 * starts with `prefix + '/'`. If no such entry exists (cold-start reload, etc.)
 * we navigate to `fallbackPath` with replace.
 */
export async function popOutOfFlow(flowPrefixes: string[], fallbackPath: string): Promise<void> {
    const entries = window.navigation.entries();
    const currentIdx = window.navigation.currentEntry?.index ?? -1;

    for (let i = currentIdx - 1; i >= 0; i--) {
        const entry = entries[i];
        if (!entry?.url) continue;
        const path = new URL(entry.url).pathname;
        const isFlow = flowPrefixes.some((p) => path === p || path.startsWith(`${p}/`));
        if (isFlow) continue;
        try {
            await window.navigation.traverseTo(entry.key).finished;
            return;
        } catch {
            break;
        }
    }

    navigate(fallbackPath, { history: 'replace' });
}

// ── Router ──────────────────────────────────────────────────────────────────

export function startRouter(
    routes: Record<string, RouteConfig>,
    target: HTMLElement,
): () => void {
    let currentRoute = '';
    let currentFullPath = '';
    let renderSequence = 0;

    async function activate(url: URL): Promise<void> {
        const path = normalizePath(url.pathname);
        const query = new URLSearchParams(url.search);
        const { route, params } = matchRoute(path, routes);

        if (route === '/' && path !== '/') {
            navigate('/', { history: 'replace' });
            return;
        }

        const fullPath = `${path}${query.toString() ? `?${query}` : ''}`;
        if (fullPath === currentFullPath) return;

        const isBack = isBackNavigation(currentRoute, route);
        currentRoute = route;
        currentFullPath = fullPath;

        if (isBack) {
            document.documentElement.classList.add('back-transition');
        } else {
            document.documentElement.classList.remove('back-transition');
        }

        const config = routes[route];
        if (!config) return;

        const activationId = ++renderSequence;
        const render = async () => {
            const screen = await config.render({ path, params, query });
            if (activationId === renderSequence) {
                target.replaceChildren(screen);
            }
        };

        if (document.startViewTransition && document.visibilityState === 'visible') {
            try {
                await document.startViewTransition(render).finished;
            } catch {
                await render();
            }
        } else {
            await render();
        }
    }

    const onNavigate = (event: NavigateEvent) => {
        if (!event.canIntercept) return;
        const destination = new URL(event.destination.url);
        if (destination.origin !== window.location.origin) return;

        event.intercept({
            scroll: 'manual',
            async handler() {
                await activate(destination);
                event.scroll();
            },
        });
    };

    window.navigation.addEventListener('navigate', onNavigate);
    void activate(new URL(window.location.href));

    return () => window.navigation.removeEventListener('navigate', onNavigate);
}

// ── Internals ───────────────────────────────────────────────────────────────

export function matchRoute(
    pathname: string,
    routes: Record<string, RouteConfig>,
): { route: string; params: Record<string, string> } {
    const path = normalizePath(pathname);

    if (path === '/') return { route: '/', params: {} };
    if (routes[path]) return { route: path, params: {} };

    for (const pattern of Object.keys(routes)) {
        if (!pattern.includes(':')) continue;

        const patternParts = pattern.split('/');
        const pathParts = path.split('/');
        if (patternParts.length !== pathParts.length) continue;

        const params: Record<string, string> = {};
        let match = true;

        for (let i = 0; i < patternParts.length; i++) {
            if (patternParts[i].startsWith(':')) {
                if (!pathParts[i]) { match = false; break; }
                params[patternParts[i].substring(1)] = pathParts[i];
            } else if (patternParts[i] !== pathParts[i]) {
                match = false;
                break;
            }
        }

        if (match) return { route: pattern, params };
    }

    return { route: '/', params: {} };
}

function isBackNavigation(fromRoute: string, toRoute: string): boolean {
    if (!fromRoute) return false;
    if (toRoute === '/' && fromRoute !== '/') return true;
    return fromRoute.startsWith(toRoute + '/');
}

function normalizePath(path: string): string {
    if (!path || path === '/') return '/';
    const p = path.startsWith('/') ? path : `/${path}`;
    return p.endsWith('/') ? p.slice(0, -1) : p;
}
